import{_ as h,o as e,c as g,j as a,a as t,a1 as b}from"./chunks/framework.Bp7r_-XI.js";const _=JSON.parse('{"title":"Waaagh能量","description":"","frontmatter":{},"headers":[],"relativePath":"4.资源分区/5.能量池/Waaagh能量.md","filePath":"4.资源分区/5.能量池/Waaagh能量.md"}'),W={name:"4.资源分区/5.能量池/Waaagh能量.md"};function p(s,r,n,o,d,l){return e(),g("div",null,[...r[0]||(r[0]=[a("h1",{id:"waaagh能量",tabindex:"-1"},[t("Waaagh能量 "),a("a",{class:"header-anchor",href:"#waaagh能量","aria-label":'Permalink to "Waaagh能量"'},"​")],-1),a("table",{class:"bannerparthead"},[a("tbody",null,[a("tr",{id:"hdr"},[a("td",{class:"runninghead",nowrap:""},"TMD：汹涌疾风020")])])],-1),b('<h1 id="waaagh能量-1" tabindex="-1">waaagh能量 <a class="header-anchor" href="#waaagh能量-1" aria-label="Permalink to &quot;waaagh能量&quot;">​</a></h1><p>waaagh能量<br> 特异本质<br> （出自战锤40K宇宙）<br> 描述：简单来说，Waaagh是一种美妙的、激情的、让人兴奋和感到他妈的燃起来了！的一种情绪，小子，我很难和你形容这种感觉。当你拿到一把涂满红漆的崭新链锯剑，这很Waaagh！当你跟着Warboss一起发动一场声势浩大的Waaagh，在无数绿皮的Waaagh之中情不自禁地Waaagh出来，这就非常非常的Waaagh。<br> 你还是听不懂？这小子废了，这辈子就这样了，拉下去找把枪丢去填线吧。<br> Waaagh是一种源自灵能植物种族“绿皮”的神秘灵能力量，它们天生的战斗智慧和主观意识的结晶，一个强大的灵能绿皮甚至可以运用Waaagh立场有限地影响现实中的物理性质（这包括带一堆茅厕组成的飞船上天），简单来说，就是“我思故我在”“意识决定物质”，说的通俗一点……<br> 俺寻思这能飞起来。<br> Waaagh能量的关键属性是【力量+耐力】，与其他能量池不同的是，该能量池在满足条件的情况下可以在战斗中恢复甚至永久提高能量池上限。<br> 这是一个西方通用能量池，特殊的，这一能量可以替代灵能来使用需要灵能的能力或者满足灵能的前置条件。</p><p>恢复方式：当人物进行一次长休息，恢复所有Waaagh能量。当人物进行一次短休息，恢复力量与耐力平均值的Waaagh能量。<br> 每日恢复的Waaagh能量不能超过能量池大小的三倍。</p><p>基础用法：消耗1点Waaagh能量，你在全检定上获得1DP俺寻思加值（士气），持续一轮。</p><p>仅当你购买研发-战争能量后，你获得新的能量恢复方式和能量池上限成长：<br> 当你正在进行的战斗满足以下条件时，每个回合开始都会恢复1点Waaagh能量。<br> 条件：<br> ①你的敌人实力与你相同或更高（依支线等级而定）<br> ②你受过伤而且成功命中过敌人。<br> ③你寻思你很牛逼。</p><p>当你正在进行的战斗满足以下条件时，战斗结束后，你的Waaagh能量池上限永久提升6点，每影片这一效果只会生效一次。<br> 条件：<br> ①你正在经历一场重要的战斗。<br> ②你的队友都觉得你很牛逼。<br> ③你寻思你很牛逼。</p><p>搞毛二哥的一根腿毛级别的Waaagh<br> 价格：D+1500<br> 描述：你成功感受到了远在天边近在眼前的Waaagh，这很牛逼，你感到浑身上下说不出来的舒畅，你甚至在遥远的天边看到了搞毛二哥的大脚丫子，你觉得总有一天自己也会像搞毛二哥那么Waaagh虽然你压根不知道自己啥时候认识的搞毛二哥。<br> 前提：力量3+<br> 效果：人物开启Waaagh能量池，关键属性为力量+耐力，同时获得基础用法。 只要Waaagh立场不为空，你就可以获得3点偏斜防御。<br> 受伤了！你寻思自己可以自愈，消耗2点Waaagh能量，该轮额外获得1点快速医疗（12医疗点数）</p><p>研发-战争能量（10XP）：绿皮的Waaagh立场是一种极其独特的灵能力量，可以在战斗中不断成长，但主神修改后的绿皮为了保持情绪稳定去除了无限成长的waaagh立场，所以需要单独对waaagh立场进行钻研重获成长性。</p><p>搞毛二哥一根小脚趾级别的Waaagh<br> 价格：C+1000<br> 描述：随着对Waaagh力场的掌握，你感觉自己已经攀登到了过去的自己无法想象的高处，登高望远，如今的你才发现，自己相比于在亚空间无限鏖战，深陷很Waaagh的Waaagh中不断变强的搞毛二哥，只犹如蜉蝣见沧海，井蛙望青天，这让你的内心充满了希望：终有一日，你也能在亚空间中品尝那庞大的Waaagh的甜美。<br> 前提：力量8+、俺寻思专业5+<br> 效果：Waaagh力场的上限提升力量属性*1点，在进行力量属性相关检定时消耗1点Waaagh能量获得1点附加成功，若如此做，则可以将这次检定中的2dp转化为1点附加成功，至多转化传奇力量点成功。<br> 获得这一效果时从以下效果中选择1种获得：<br> 每回合开始时，你寻思敌人的攻击会打偏，主动消耗6点Waaagh能量，本轮内获得5点偏斜防御<br> 一轮一次，结合在一次攻击中，消耗6点Waaagh能量，这次攻击额外具有【威猛5】，这些威猛在计算破防后若仍有剩余则可以将剩余量转化为攻击上的俺寻思加值（士气）</p><hr><p>Copyright ? 2024 <a href="http://www.goddessfantasy.net/bbs/index.php?board=2008.0" target="_blank" rel="noreferrer">TMDtrpg制作组</a>. All Rights Reserved.</p>',11)])])}const c=h(W,[["render",p]]);export{_ as __pageData,c as default};
